<?php
require __DIR__ . '/lib.php';
if (!is_admin()) redirect('admin.php');
$items = load_content('inquiries');
$id = (string)($_GET['id'] ?? '');
$selected = null;
foreach ($items as $key => $item) if (($item['id'] ?? '') === $id) { $selected=$item; if(($item['status']??'new')==='new'){$items[$key]['status']='read';save_content('inquiries',$items);} break; }
?><!doctype html><html lang="ja"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>お問い合わせ管理｜<?=e(APP_NAME)?></title><link rel="stylesheet" href="assets/admin.css"><link rel="stylesheet" href="assets/admin-menu-fix.css?v=2"><link rel="stylesheet" href="assets/inquiries-admin.css"></head><body class="admin-shell"><aside><a class="admin-logo" href="admin.php">HIT OKINAWA<small>CONTENT MANAGEMENT</small></a><nav></nav></aside><script src="assets/admin-nav.js?v=5" defer></script><main class="admin-main"><header><div><p>PRO CHUBO HIT OKINAWA</p><h1>お問い合わせ</h1></div><a href="contact.php" target="_blank">フォームを確認 ↗</a></header><div class="inquiry-layout"><section class="panel inquiry-list"><h2><?=count($items)?>件</h2><?php if(!$items):?><p>お問い合わせはまだありません。</p><?php endif;?><?php foreach($items as $item):?><a class="<?=($item['id']??'')===$id?'active':''?>" href="?id=<?=e($item['id']??'')?>"><span class="inquiry-status <?=e($item['status']??'new')?>"><?=($item['status']??'new')==='new'?'未読':'既読'?></span><strong><?=e($item['name']??'')?></strong><small><?=e($item['type']??'')?>　<?=e(substr((string)($item['created_at']??''),0,10))?></small></a><?php endforeach;?></section><?php if($selected):?><section class="panel inquiry-detail"><p class="inquiry-id"><?=e($selected['id'])?></p><h2><?=e($selected['name'])?> 様</h2><dl><div><dt>相談種別</dt><dd><?=e($selected['type'])?></dd></div><div><dt>会社・店舗名</dt><dd><?=e($selected['company']?:'—')?></dd></div><div><dt>電話</dt><dd><a href="tel:<?=e($selected['phone'])?>"><?=e($selected['phone'])?></a></dd></div><div><dt>メール</dt><dd><a href="mailto:<?=e($selected['email'])?>"><?=e($selected['email'])?></a></dd></div><div><dt>受信日時</dt><dd><?=e($selected['created_at'])?></dd></div><div><dt>メール通知</dt><dd><?=!empty($selected['mail_sent'])?'送信済み':'未送信（受信データは保存済み）'?></dd></div></dl><div class="inquiry-message"><?=nl2br(e($selected['message']))?></div></section><?php endif;?></div></main></body></html>
